```python
def parse_nested_parens(paren_string: str) -> List[int]:
    results = []
    for group in paren_string.split():
        max_depth = 0
        current_depth = 0
        for char in group:
            if char == '(':
                current_depth += 1
                max_depth = max(max_depth, current_depth)
            elif char == ')':
                current_depth -= 1
        results.append(max_depth)
    return results
```

```python
def parse_nested_parens(paren_string: str) -> List[int]:
    def max_nesting_level(group: str) -> int:
        current_level = 0
        max_level = 0
        for char in group:
            if char == '(':
                current_level += 1
                max_level = max(max_level, current_level)
            elif char == ')':
                current_level -= 1
        return max_level

    return [max_nesting_level(group) for group in paren_string.split()]
```

